403: bool DefaultCertValidator::verifyCertificateHashList(
404:     X509* cert, const std::vector<std::vector<uint8_t>>& expected_hashes) {
405:   std::vector<uint8_t> computed_hash(SHA256_DIGEST_LENGTH);
406:   unsigned int n;
407:   X509_digest(cert, EVP_sha256(), computed_hash.data(), &n);
408:   RELEASE_ASSERT(n == computed_hash.size(), "");
409: 
410:   for (const auto& expected_hash : expected_hashes) {
411:     if (computed_hash == expected_hash) {
412:       return true;
413:     }
414:   }
415:   return false;
416: }
