91: ServerContextImpl::ServerContextImpl(Stats::Scope& scope,
92:                                      const Envoy::Ssl::ServerContextConfig& config,
93:                                      const std::vector<std::string>& server_names,
94:                                      Server::Configuration::CommonFactoryContext& factory_context,
95:                                      Ssl::ContextAdditionalInitFunc additional_init,
96:                                      absl::Status& creation_status)
97:     : ContextImpl(scope, config, factory_context, additional_init, creation_status),
98:       session_ticket_keys_(config.sessionTicketKeys()),
99:       ocsp_staple_policy_(config.ocspStaplePolicy()),
100:       full_scan_certs_on_sni_mismatch_(config.fullScanCertsOnSNIMismatch()) {
101:   if (!creation_status.ok()) {
102:     return;
103:   }
104:   if (config.tlsCertificates().empty() && !config.capabilities().provides_certificates) {
105:     creation_status =
106:         absl::InvalidArgumentError("Server TlsCertificates must have a certificate specified");
107:     return;
108:   }
109: 
110:   for (auto& ctx : tls_contexts_) {
111:     if (ctx.cert_chain_ == nullptr) {
112:       continue;
113:     }
114:     bssl::UniquePtr<EVP_PKEY> public_key(X509_get_pubkey(ctx.cert_chain_.get()));
115:     const int pkey_id = EVP_PKEY_id(public_key.get());
116:     // Load DNS SAN entries and Subject Common Name as server name patterns after certificate
117:     // chain loaded, and populate ServerNamesMap which will be used to match SNI.
118:     has_rsa_ |= (pkey_id == EVP_PKEY_RSA);
119:     populateServerNamesMap(ctx, pkey_id);
120:   }
121: 
122:   // Compute the session context ID hash. We use all the certificate identities,
123:   // since we should have a common ID for session resumption no matter what cert
124:   // is used. We do this early because it can fail.
125:   absl::StatusOr<SessionContextID> id_or_error = generateHashForSessionContextId(server_names);
126:   SET_AND_RETURN_IF_NOT_OK(id_or_error.status(), creation_status);
127:   const SessionContextID& session_id = *id_or_error;
128: 
129:   // First, configure the base context for ClientHello interception.
130:   // TODO(htuch): replace with SSL_IDENTITY when we have this as a means to do multi-cert in
131:   // BoringSSL.
132:   if (!config.capabilities().provides_certificates) {
133:     SSL_CTX_set_select_certificate_cb(
134:         tls_contexts_[0].ssl_ctx_.get(),
135:         [](const SSL_CLIENT_HELLO* client_hello) -> ssl_select_cert_result_t {
136:           return static_cast<ServerContextImpl*>(
137:                      SSL_CTX_get_app_data(SSL_get_SSL_CTX(client_hello->ssl)))
138:               ->selectTlsContext(client_hello);
139:         });
140:   }
141: 
142:   const auto tls_certificates = config.tlsCertificates();
143: 
144:   for (uint32_t i = 0; i < tls_certificates.size(); ++i) {
145:     auto& ctx = tls_contexts_[i];
146:     if (!config.capabilities().verifies_peer_certificates) {
147:       SET_AND_RETURN_IF_NOT_OK(cert_validator_->addClientValidationContext(
148:                                    ctx.ssl_ctx_.get(), config.requireClientCertificate()),
149:                                creation_status);
150:     }
