71: void SslSocket::setTransportSocketCallbacks(Network::TransportSocketCallbacks& callbacks) {
72:   ASSERT(!callbacks_);
73:   callbacks_ = &callbacks;
74: 
75:   // Associate this SSL connection with all the certificates (with their potentially different
76:   // private key methods).
77:   for (auto const& provider : ctx_->getPrivateKeyMethodProviders()) {
78:     provider->registerPrivateKeyMethod(rawSsl(), *this, callbacks_->connection().dispatcher());
79:   }
