82:   BIO* bio = BIO_new_io_handle(&callbacks_->ioHandle());
83:   SSL_set_bio(rawSsl(), bio, bio);
84:   SSL_set_ex_data(rawSsl(), ContextImpl::sslSocketIndex(), static_cast<void*>(callbacks_));
