87: SslSocket::ReadResult SslSocket::sslReadIntoSlice(Buffer::RawSlice& slice) {
88:   ReadResult result;
89:   uint8_t* mem = static_cast<uint8_t*>(slice.mem_);
90:   size_t remaining = slice.len_;
91:   while (remaining > 0) {
92:     int rc = SSL_read(rawSsl(), mem, remaining);
93:     ENVOY_CONN_LOG(trace, "ssl read returns: {}", callbacks_->connection(), rc);
94:     if (rc > 0) {
95:       ASSERT(static_cast<size_t>(rc) <= remaining);
96:       mem += rc;
97:       remaining -= rc;
98:       result.bytes_read_ += rc;
99:     } else {
100:       result.error_ = absl::make_optional<int>(rc);
101:       break;
102:     }
103:   }
104: 
105:   return result;
106: }
