108: Network::IoResult SslSocket::doRead(Buffer::Instance& read_buffer) {
109:   if (info_->state() != Ssl::SocketState::HandshakeComplete &&
110:       info_->state() != Ssl::SocketState::ShutdownSent) {
111:     PostIoAction action = doHandshake();
112:     if (action == PostIoAction::Close || info_->state() != Ssl::SocketState::HandshakeComplete) {
113:       // end_stream is false because either a hard error occurred (action == Close) or
114:       // the handshake isn't complete, so a half-close cannot occur yet.
115:       return {action, 0, false};
116:     }
117:   }
118: 
119:   bool keep_reading = true;
120:   bool end_stream = false;
121:   PostIoAction action = PostIoAction::KeepOpen;
122:   uint64_t bytes_read = 0;
123:   while (keep_reading) {
124:     uint64_t bytes_read_this_iteration = 0;
125:     Buffer::Reservation reservation = read_buffer.reserveForRead();
126:     for (uint64_t i = 0; i < reservation.numSlices(); i++) {
127:       auto result = sslReadIntoSlice(reservation.slices()[i]);
128:       bytes_read_this_iteration += result.bytes_read_;
129:       if (result.error_.has_value()) {
130:         keep_reading = false;
131:         int err = SSL_get_error(rawSsl(), result.error_.value());
132:         ENVOY_CONN_LOG(trace, "ssl error occurred while read: {}", callbacks_->connection(),
133:                        Utility::getErrorDescription(err));
134:         switch (err) {
135:         case SSL_ERROR_WANT_READ:
136:           break;
137:         case SSL_ERROR_ZERO_RETURN:
138:           // Graceful shutdown using close_notify TLS alert.
139:           end_stream = true;
140:           break;
141:         case SSL_ERROR_SYSCALL:
142:           if (result.error_.value() == 0) {
143:             // Non-graceful shutdown by closing the underlying socket.
144:             end_stream = true;
145:             break;
146:           }
147:           FALLTHRU;
148:         case SSL_ERROR_WANT_WRITE:
149:           // Renegotiation has started. We don't handle renegotiation so just fall through.
150:         default:
151:           drainErrorQueue();
152:           action = PostIoAction::Close;
153:           break;
154:         }
155: 
156:         break;
157:       }
158:     }
159: 
160:     reservation.commit(bytes_read_this_iteration);
161:     if (bytes_read_this_iteration > 0 && callbacks_->shouldDrainReadBuffer()) {
162:       callbacks_->setTransportSocketIsReadable();
163:       keep_reading = false;
164:     }
165: 
166:     bytes_read += bytes_read_this_iteration;
167:   }
168: 
169:   ENVOY_CONN_LOG(trace, "ssl read {} bytes", callbacks_->connection(), bytes_read);
170: 
171:   return {action, bytes_read, end_stream};
172: }
